import { describe, expect, it } from 'vitest';

import {
  admitVisualWatermarkMeshIdentity,
  admittedVisualWatermarkToken,
  visualWatermarkMeshIdentityMasterRuntime,
} from '../src/visual-watermark-mesh-identity';

describe('visual watermark mesh identity admission', () => {
  it('admits issued visual watermark tokens only when correlation clears', () => {
    const admitted = admitVisualWatermarkMeshIdentity(
      { token: 69, correlation: 0.92 },
      { threshold: 0.5 },
    );

    expect(admitted.outcome).toBe('claim_admitted');
    expect(admitted.limitation).toBe('none');
    expect(admitted.correlationCleared).toBe(true);
    expect(admitted.tokenAdmitted).toBe(true);
  });

  it('withholds forged visual watermark tokens even at high correlation', () => {
    const forged = admitVisualWatermarkMeshIdentity(
      { token: 7, correlation: 0.92 },
      { threshold: 0.5 },
    );

    expect(forged.outcome).toBe('claim_withheld');
    expect(forged.limitation).toBe('forged_token');
    expect(forged.correlationCleared).toBe(true);
    expect(forged.tokenAdmitted).toBe(false);
  });

  it('withholds admitted tokens when visual correlation is weak', () => {
    const weak = admitVisualWatermarkMeshIdentity(
      { token: 69, correlation: 0.49 },
      { threshold: 0.5 },
    );

    expect(weak.outcome).toBe('claim_withheld');
    expect(weak.limitation).toBe('weak_correlation');
    expect(weak.correlationCleared).toBe(false);
    expect(weak.tokenAdmitted).toBe(true);
  });

  it('keeps the finite runtime witness aligned with mesh-issued tokens', () => {
    expect(admittedVisualWatermarkToken(69)).toBe(true);
    expect(admittedVisualWatermarkToken(66)).toBe(true);
    expect(admittedVisualWatermarkToken(660)).toBe(true);
    expect(admittedVisualWatermarkToken(7)).toBe(false);
    expect(visualWatermarkMeshIdentityMasterRuntime()).toEqual({
      genuineAdmitted: true,
      forgedRejected: true,
      weakRejected: true,
    });
  });
});
